    A = list(map(int, sys.stdin.readline().split()))

    res = 0
    for i in range(n):
        lo, hi = i, i
        while hi < n and A[hi] - A[lo] <= r:
            hi += 1
        while lo < hi and A[hi-1] - A[lo] > r:
            lo += 1
        for j in range(lo, hi):
            sum = 0
            for k in range(j, hi):
                sum += A[k]
                if sum > s:
                    break
                res += 1

    print(res)

if __name__ == '__main__':
