    a = list(map(int, sys.stdin.readline().split()))

    ans = 0
    i = 0
    while i < n:
        lo = i
        hi = i
        for j in range(i, n):
            hi = j
            while lo < j:
                mid = (lo + hi + 1) // 2
                if a[mid] - a[lo] <= r and a[j] - a[mid] <= r:
                    lo = mid
                else:
                    break
            if a[j] - a[lo] <= r:
                break
        j -= 1
        if a[j] - a[i] <= r:
            while i <= j and a[i] - a[i] <= r and sum(a[i:j+1]) <= s:
                i += 1
            ans += j - i + 1
        else:
            i = j + 1

    print(ans)

if __name__ == "__main__":
    main()
